// CustomMetrics holds all our Prometheus metrics for per-user, per-request tracking
type CustomMetrics struct {
	requestsTotal    *prometheus.CounterVec
	requestDuration  *prometheus.HistogramVec
	requestsInFlight *prometheus.GaugeVec
	responseSize     *prometheus.SummaryVec
	errorsTotal      *prometheus.CounterVec
	userActiveGauge  *prometheus.GaugeVec
}

// NewCustomMetrics creates and registers all custom metrics
func NewCustomMetrics(reg prometheus.Registerer) *CustomMetrics {
	m := &CustomMetrics{
		requestsTotal: prometheus.NewCounterVec(
			prometheus.CounterOpts{
				Namespace: "app",
				Subsystem: "http",
				Name:      "requests_total",
				Help:      "Total number of HTTP requests processed, partitioned by user, method, endpoint, and status.",
			},
			[]string{"user_id", "method", "endpoint", "status_code", "user_agent", "region"},
		),
		requestDuration: prometheus.NewHistogramVec(
			prometheus.HistogramOpts{
				Namespace: "app",
				Subsystem: "http",
				Name:      "request_duration_seconds",
				Help:      "Histogram of request durations in seconds, partitioned by user, method, and endpoint.",
				Buckets:   prometheus.DefBuckets,
			},
			[]string{"user_id", "method", "endpoint", "region"},
		),
		requestsInFlight: prometheus.NewGaugeVec(
			prometheus.GaugeOpts{
				Namespace: "app",
				Subsystem: "http",
				Name:      "requests_in_flight",
				Help:      "Current number of in-flight requests per user.",
			},
			[]string{"user_id", "endpoint"},
		),
		responseSize: prometheus.NewSummaryVec(
			prometheus.SummaryOpts{
				Namespace:  "app",
				Subsystem:  "http",
				Name:       "response_size_bytes",
				Help:       "Summary of response sizes in bytes per user and endpoint.",
				Objectives: map[float64]float64{0.5: 0.05, 0.9: 0.01, 0.99: 0.001},
			},
			[]string{"user_id", "endpoint", "content_type"},
		),
		errorsTotal: prometheus.NewCounterVec(
			prometheus.CounterOpts{
				Namespace: "app",
				Subsystem: "http",
				Name:      "errors_total",
				Help:      "Total number of errors encountered, partitioned by user, endpoint, and error type.",
			},
			[]string{"user_id", "endpoint", "error_type", "region"},
		),
		userActiveGauge: prometheus.NewGaugeVec(
			prometheus.GaugeOpts{
				Namespace: "app",
				Subsystem: "user",
				Name:      "active_sessions",
				Help:      "Number of active sessions per user and region.",
			},
			[]string{"user_id", "region", "subscription_tier"},
		),
	}

	reg.MustRegister(
		m.requestsTotal,
		m.requestDuration,
		m.requestsInFlight,
		m.responseSize,
		m.errorsTotal,
		m.userActiveGauge,
	)

	return m
}

// RequestInfo holds user-provided values used as metric labels
type RequestInfo struct {
	UserID           string
	Method           string
	Endpoint         string
	StatusCode       string
	UserAgent        string
	Region           string
	ContentType      string
	ErrorType        string
	SubscriptionTier string
}

// TrackRequest records all metrics for a single request
func (m *CustomMetrics) TrackRequest(info RequestInfo, duration time.Duration, responseBytes float64, isError bool) {
	m.requestsTotal.With(prometheus.Labels{
		"user_id":    info.UserID,
		"method":     info.Method,
		"endpoint":   info.Endpoint,
		"status_code": info.StatusCode,
		"user_agent": info.UserAgent,
		"region":     info.Region,
	}).Inc()

	m.requestDuration.With(prometheus.Labels{
		"user_id":  info.UserID,
		"method":   info.Method,
		"endpoint": info.Endpoint,
		"region":   info.Region,
	}).Observe(duration.Seconds())

	m.responseSize.With(prometheus.Labels{
		"user_id":      info.UserID,
		"endpoint":     info.Endpoint,
		"content_type": info.ContentType,
	}).Observe(responseBytes)

	if isError {
		m.errorsTotal.With(prometheus.Labels{
			"user_id":    info.UserID,
			"endpoint":   info.Endpoint,
			"error_type": info.ErrorType,
			"region":     info.Region,
		}).Inc()
	}
}

// TrackInFlight increments in-flight gauge before request and decrements after
func (m *CustomMetrics) TrackInFlight(userID, endpoint string) func() {
	g := m.requestsInFlight.With(prometheus.Labels{
		"user_id":  userID,
		"endpoint": endpoint,
	})
	g.Inc()
	return func() {
		g.Dec()
	}
}

// SetActiveSessions sets the active session count for a user
func (m *CustomMetrics) SetActiveSessions(userID, region, tier string, count float64) {
	m.userActiveGauge.With(prometheus.Labels{
		"user_id":           userID,
		"region":            region,
		"subscription_tier": tier,
	}).Set(count)
}

// instrumentedHandler wraps an HTTP handler to automatically track metrics
func instrumentedHandler(metrics *CustomMetrics, endpoint string, handler http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		userID := r.Header.Get("X-User-ID")
		if userID == "" {
			userID = r.URL.Query().Get("user_id")
		}
		if userID == "" {
			userID = "anonymous"
		}

		region := r.Header.Get("X-Region")
		if region == "" {
			region = r.URL.Query().Get("region")
		}
		if region == "" {
			region = "unknown"
		}

		tier := r.Header.Get("X-Subscription-Tier")
		if tier == "" {
			tier = r.URL.Query().Get("tier")
		}
		if tier == "" {
			tier = "free"
		}

		// Track in-flight
		done := metrics.TrackInFlight(userID, endpoint)
		defer done()

		// Record start time
		start := time.Now()

		// Use a response writer wrapper to capture status code and size
		rw := &responseWriterWrapper{ResponseWriter: w, statusCode: http.StatusOK}

		// Serve the actual request
		handler(rw, r)

		duration := time.Since(start)

		statusCode := fmt.Sprintf("%d", rw.statusCode)
		isError := rw.statusCode >= 400
		errorType := ""
		if rw.statusCode >= 400 && rw.statusCode < 500 {
			errorType = "client_error"
		} else if rw.statusCode >= 500 {
			errorType = "server_error"
		}

		info := RequestInfo{
			UserID:           userID,
			Method:           r.Method,
			Endpoint:         endpoint,
			StatusCode:       statusCode,
			UserAgent:        r.UserAgent(),
			Region:           region,
			ContentType:      rw.Header().Get("Content-Type"),
			ErrorType:        errorType,
			SubscriptionTier: tier,
		}

		metrics.TrackRequest(info, duration, float64(rw.bytesWritten), isError)
		metrics.SetActiveSessions(userID, region, tier, 1)
	}
}

// responseWriterWrapper captures status code and bytes written
type responseWriterWrapper struct {
	http.ResponseWriter
	statusCode   int
	bytesWritten int
}

func (rw *responseWriterWrapper) WriteHeader(code int) {
	rw.statusCode = code
	rw.ResponseWriter.WriteHeader(code)
}

func (rw *responseWriterWrapper) Write(b []byte) (int, error) {
	n, err := rw.ResponseWriter.Write(b)
	rw.bytesWritten += n
	return n, err
}

